def sieve_of_eratosthenes(n):
    if n < 2:
        return []

    primes = [True] * (n + 1)
    primes[0] = primes[1] = False

    p = 2
    while (p * p <= n):
        if (primes[p] == True):
            for i in range(p * p, n + 1, p):
                primes[i] = False
        p += 1

    result = []
    for p in range(n + 1):
        if primes[p]:
            result.append(p)
    return result

if __name__ == '__main__':
    # Örnek kullanım: 30'a kadar olan asal sayıları bulalım
    limit = 30
    prime_numbers = sieve_of_eratosthenes(limit)
    print(f"{limit}'e kadar olan asal sayılar: {prime_numbers}")

